#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, value;
        scanf("%d %d", &N, &value);
        int *cnt = (int *)calloc(value, sizeof(int));
        for (int i = 0; i < N; ++i) {
            long long x;
            scanf("%lld", &x);
            int r = (int)((x % value + value) % value);
            cnt[r]++;
        }
        int mex = 0;
        while (1) {
            int r = mex % value;
            if (cnt[r] == 0) break;
            cnt[r]--;
            ++mex;
        }
        printf("%d\n", mex);
        free(cnt);
    }
    return 0;
}

