int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N, value; cin >> N >> value;
        vector<int> cnt(value, 0);
        for (int i = 0; i < N; ++i) {
            long long x; cin >> x;
            int r = (int)((x % value + value) % value);
            ++cnt[r];
        }
        int mex = 0;
        while (true) {
            int r = mex % value;
            if (cnt[r] == 0) break;
            --cnt[r];
            ++mex;
        }
        cout << mex << '\n';
    }
    return 0;
}

